     1→/**
     2→ * Weight Unit Conversion Utilities
     3→ *
     4→ * Feature: 040-supabase-migration
     5→ * Task: T032
     6→ *
     7→ * Helper functions for converting between weight units (g, oz, lb)
     8→ * per FR-012: System MUST store weight in grams and support display
     9→ * in grams, ounces, or pounds.
    10→ */
    11→
    12→import type { WeightUnit } from '@/types/gear';
    13→
    14→// =============================================================================
    15→// Constants
    16→// =============================================================================
    17→
    18→/** Grams per ounce */
    19→const GRAMS_PER_OUNCE = 28.3495;
    20→
    21→/** Grams per pound */
    22→const GRAMS_PER_POUND = 453.592;
    23→
    24→/** Ounces per pound */
    25→const OUNCES_PER_POUND = 16;
    26→
    27→// =============================================================================
    28→// Conversion Functions
    29→// =============================================================================
    30→
    31→/**
    32→ * Convert grams to ounces
    33→ */
    34→export function gramsToOunces(grams: number): number {
    35→  return grams / GRAMS_PER_OUNCE;
    36→}
    37→
    38→/**
    39→ * Convert grams to pounds
    40→ */
    41→export function gramsToPounds(grams: number): number {
    42→  return grams / GRAMS_PER_POUND;
    43→}
    44→
    45→/**
    46→ * Convert ounces to grams
    47→ */
    48→export function ouncesToGrams(ounces: number): number {
    49→  return ounces * GRAMS_PER_OUNCE;
    50→}
    51→
    52→/**
    53→ * Convert pounds to grams
    54→ */
    55→export function poundsToGrams(pounds: number): number {
    56→  return pounds * GRAMS_PER_POUND;
    57→}
    58→
    59→/**
    60→ * Convert ounces to pounds
    61→ */
    62→export function ouncesToPounds(ounces: number): number {
    63→  return ounces / OUNCES_PER_POUND;
    64→}
    65→
    66→/**
    67→ * Convert pounds to ounces
    68→ */
    69→export function poundsToOunces(pounds: number): number {
    70→  return pounds * OUNCES_PER_POUND;
    71→}
    72→
    73→// =============================================================================
    74→// Generic Conversion
    75→// =============================================================================
    76→
    77→/**
    78→ * Convert a weight value from one unit to another
    79→ */
    80→export function convertWeight(value: number, from: WeightUnit, to: WeightUnit): number {
    81→  if (from === to) return value;
    82→
    83→  // First convert to grams
    84→  let grams: number;
    85→  switch (from) {
    86→    case 'g':
    87→      grams = value;
    88→      break;
    89→    case 'oz':
    90→      grams = ouncesToGrams(value);
    91→      break;
    92→    case 'lb':
    93→      grams = poundsToGrams(value);
    94→      break;
    95→    default:
    96→      throw new Error(`Unknown weight unit: ${from}`);
    97→  }
    98→
    99→  // Then convert to target unit
   100→  switch (to) {
   101→    case 'g':
   102→      return grams;
   103→    case 'oz':
   104→      return gramsToOunces(grams);
   105→    case 'lb':
   106→      return gramsToPounds(grams);
   107→    default:
   108→      throw new Error(`Unknown weight unit: ${to}`);
   109→  }
   110→}
   111→
   112→/**
   113→ * Convert a weight value to grams (for storage)
   114→ */
   115→export function toGrams(value: number, unit: WeightUnit): number {
   116→  return convertWeight(value, unit, 'g');
   117→}
   118→
   119→/**
   120→ * Convert a weight value from grams (for display)
   121→ */
   122→export function fromGrams(grams: number, unit: WeightUnit): number {
   123→  return convertWeight(grams, 'g', unit);
   124→}
   125→
   126→// =============================================================================
   127→// Formatting Functions
   128→// =============================================================================
   129→
   130→/**
   131→ * Format a weight value with its unit suffix
   132→ *
   133→ * @param value - The weight value
   134→ * @param unit - The weight unit
   135→ * @param precision - Number of decimal places (default: 1)
   136→ * @returns Formatted string like "123.4 g" or "4.3 oz"
   137→ */
   138→export function formatWeight(value: number, unit: WeightUnit, precision: number = 1): string {
   139→  const formatted = value.toFixed(precision);
   140→  return `${formatted} ${unit}`;
   141→}
   142→
   143→/**
   144→ * Format a weight value stored in grams for display in a specific unit
   145→ *
   146→ * @param grams - The weight in grams
   147→ * @param displayUnit - The unit to display in
   148→ * @param precision - Number of decimal places (default: 1)
   149→ * @returns Formatted string like "123.4 g" or "4.3 oz"
   150→ */
   151→export function formatWeightFromGrams(
   152→  grams: number,
   153→  displayUnit: WeightUnit,
   154→  precision: number = 1
   155→): string {
   156→  const value = fromGrams(grams, displayUnit);
   157→  return formatWeight(value, displayUnit, precision);
   158→}
   159→
   160→/**
   161→ * Parse a weight string to a number
   162→ * Handles various formats: "123", "123.4", "123.4g", "123.4 g", etc.
   163→ *
   164→ * @param input - The input string
   165→ * @returns The parsed number, or null if invalid
   166→ */
   167→export function parseWeight(input: string): number | null {
   168→  if (!input) return null;
   169→
   170→  // Remove unit suffix and whitespace
   171→  const cleaned = input.replace(/\s*(g|oz|lb)s?\s*$/i, '').trim();
   172→
   173→  // Parse as float
   174→  const value = parseFloat(cleaned);
   175→
   176→  if (isNaN(value) || !isFinite(value)) {
   177→    return null;
   178→  }
   179→
   180→  return value;
   181→}
   182→
   183→// =============================================================================
   184→// Weight Summary for Loadouts
   185→// =============================================================================
   186→
   187→export interface WeightSummary {
   188→  /** Total weight of all items */
   189→  totalWeight: number;
   190→  /** Base weight (total - worn - consumable) */
   191→  baseWeight: number;
   192→  /** Weight of worn items */
   193→  wornWeight: number;
   194→  /** Weight of consumable items */
   195→  consumableWeight: number;
   196→}
   197→
   198→/**
   199→ * Calculate a weight summary with all values in grams
   200→ */
   201→export function calculateWeightSummary(
   202→  totalGrams: number,
   203→  wornGrams: number,
   204→  consumableGrams: number
   205→): WeightSummary {
   206→  return {
   207→    totalWeight: totalGrams,
   208→    baseWeight: totalGrams - wornGrams - consumableGrams,
   209→    wornWeight: wornGrams,
   210→    consumableWeight: consumableGrams,
   211→  };
   212→}
